previewCss:
.darma-loader-darma-custom-549 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #38bdf8);
   width: 60px;
   height: 20px;
   display: grid;
   color: var(--loader-color, #2563eb);
}
.darma-loader-darma-custom-549:before, .darma-loader-darma-custom-549:after  {
  content: "";
   grid-area: 1/1;
   --c:#0000 calc(100%/3),var(--loader-color, #2563eb) 0 calc(2*100%/3),#0000 0;
   --c1:linear-gradient(90deg,var(--c));
   --c2:linear-gradient( 0deg,var(--c));
   background: var(--c1),var(--c2),var(--c1),var(--c2);
   background-size: 300% 4px,4px 300%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-549-l15 1.5s infinite;
}
.darma-loader-darma-custom-549:after  {
  animation-delay: -.75s;
}
@keyframes darma-loader-darma-custom-549-l15  {
  0% {background-position: 50% 0,100% 100%,0 100%,0 0}
25% {background-position: 0 0,100% 50% ,0 100%,0 0}
50% {background-position: 0 0,100% 0 ,50% 100%,0 0}
75% {background-position: 0 0,100% 0 ,100% 100%,0 50%}
75.01%{background-position: 100% 0,100% 0 ,100% 100%,0 50%}
100% {background-position: 50% 0,100% 0 ,100% 100%,0 100%}
}

